  <div class="col-sm-3">
    <div class="stat-card">
      <div class="stat-num text-dark">{{ total_all }}</div>
      <div class="stat-label">Total classes held</div>
    </div>
  </div>
</div>

<div class="row g-4 mb-4">
  <div class="col-md-8">
    <div class="card h-100">
      <div class="card-header px-4 py-3">Attendance % per student</div>
      <div class="card-body px-4 py-3">
        {% if students %}<canvas id="barChart" height="90"></canvas>
        {% else %}<div class="text-center text-muted py-4">No student data yet.</div>{% endif %}
