      <span class="fw-500">Claude AI — class report</span>
    </div>
    <button id="generate-btn" class="btn btn-dark btn-sm px-3" onclick="generateClassInsight()">
      Generate class report
    </button>
  </div>
  <div class="card-body px-4 py-4">
    <div id="insight-placeholder" class="text-center text-muted py-3" style="font-size:.9rem">
      Click "Generate class report" to get an AI analysis of your entire class.
    </div>
    <div id="insight-loading" style="display:none" class="text-center py-3">
      <div class="spinner-border spinner-border-sm text-secondary me-2"></div>
      <span class="text-muted small">Claude is analysing your class data...</span>
    </div>
