@app.route("/api/readme", methods=["POST"])
def get_readme():
    data = request.json
    repo_key = data.get("repo_key", "")

    repo = repo_store.get(repo_key)
    if not repo:
        return jsonify({"error": "Repo not found"}), 404

    try:
